WITH params AS (SELECT ((now() AT TIME ZONE 'Asia/Ho_Chi_Minh')::date - 14) AS start_date, ((now() AT TIME ZONE 'Asia/Ho_Chi_Minh')::date + 14) AS end_date), target_rows AS (SELECT dp.id, dp.plan_date, dp.product_id, p.sku, p.name AS product_name, dp.customer_id, c.code AS customer_code, c.name AS customer_name, dp.delivery_customer_id, dc.code AS delivery_customer_code, dc.name AS delivery_customer_name, public.delivery_point_key(dp.customer_id, dp.delivery_customer_id) AS delivery_key, dp.planned_qty, dp.backlog_qty, dp.actual_qty, dp.is_backlog, dp.backlog_source, dp.is_completed, dp.note, dp.note_2, dp.note_edited_at, dp.note_2_edited_at, dp.updated_at, dp.created_at FROM public.delivery_plans dp JOIN public.products p ON p.id = dp.product_id LEFT JOIN public.customers c ON c.id = dp.customer_id LEFT JOIN public.customers dc ON dc.id = dp.delivery_customer_id CROSS JOIN params WHERE dp.deleted_at IS NULL AND dp.plan_date BETWEEN params.start_date AND params.end_date), audit AS (SELECT tr.*, prev1.plan_date AS latest_note_plan_date, prev1.note AS latest_note_before, prev1.note_edited_at AS latest_note_edited_at_before, prev2.plan_date AS latest_note_2_plan_date, prev2.note_2 AS latest_note_2_before, prev2.note_2_edited_at AS latest_note_2_edited_at_before FROM target_rows tr LEFT JOIN LATERAL (SELECT dp.plan_date, dp.note, dp.note_edited_at FROM public.delivery_plans dp WHERE dp.deleted_at IS NULL AND dp.product_id = tr.product_id AND public.delivery_point_key(dp.customer_id, dp.delivery_customer_id) = tr.delivery_key AND dp.plan_date < tr.plan_date AND dp.note_edited_at IS NOT NULL ORDER BY dp.plan_date DESC, dp.note_edited_at DESC NULLS LAST, dp.updated_at DESC NULLS LAST, dp.created_at DESC NULLS LAST LIMIT 1) prev1 ON true LEFT JOIN LATERAL (SELECT dp.plan_date, dp.note_2, dp.note_2_edited_at FROM public.delivery_plans dp WHERE dp.deleted_at IS NULL AND dp.product_id = tr.product_id AND public.delivery_point_key(dp.customer_id, dp.delivery_customer_id) = tr.delivery_key AND dp.plan_date < tr.plan_date AND dp.note_2_edited_at IS NOT NULL ORDER BY dp.plan_date DESC, dp.note_2_edited_at DESC NULLS LAST, dp.updated_at DESC NULLS LAST, dp.created_at DESC NULLS LAST LIMIT 1) prev2 ON true) SELECT CASE WHEN latest_note_edited_at_before IS NOT NULL AND note_edited_at IS NOT NULL AND note_edited_at < latest_note_edited_at_before AND note IS DISTINCT FROM latest_note_before THEN 'note_1_stale_current_row_older_than_latest_before' WHEN latest_note_2_edited_at_before IS NOT NULL AND note_2_edited_at IS NOT NULL AND note_2_edited_at < latest_note_2_edited_at_before AND note_2 IS DISTINCT FROM latest_note_2_before THEN 'note_2_stale_current_row_older_than_latest_before' WHEN note_edited_at IS NOT NULL AND note ILIKE 'Backlog%' THEN 'note_1_backlog_text_marked_as_edited' WHEN note_2_edited_at IS NOT NULL AND note_2 ILIKE 'Backlog%' THEN 'note_2_backlog_text_marked_as_edited' ELSE 'check' END AS audit_reason, plan_date, sku, product_name, customer_code, customer_name, delivery_customer_code, delivery_customer_name, planned_qty, backlog_qty, actual_qty, is_backlog, backlog_source, is_completed, note, note_edited_at, latest_note_before, latest_note_edited_at_before, latest_note_plan_date, note_2, note_2_edited_at, latest_note_2_before, latest_note_2_edited_at_before, latest_note_2_plan_date, id FROM audit WHERE (latest_note_edited_at_before IS NOT NULL AND note_edited_at IS NOT NULL AND note_edited_at < latest_note_edited_at_before AND note IS DISTINCT FROM latest_note_before) OR (latest_note_2_edited_at_before IS NOT NULL AND note_2_edited_at IS NOT NULL AND note_2_edited_at < latest_note_2_edited_at_before AND note_2 IS DISTINCT FROM latest_note_2_before) OR (note_edited_at IS NOT NULL AND note ILIKE 'Backlog%') OR (note_2_edited_at IS NOT NULL AND note_2 ILIKE 'Backlog%') ORDER BY plan_date DESC, sku, delivery_customer_code NULLS FIRST;
